INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-f29af906-moex-00518', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '徵收土地時，其土地改良物應一併徵收。但特定情形，不在此限。依土地徵收條例規定，下列何者 非屬該特定情形？', '["建築改良物依法令規定不得建造者", "墳墓及其他紀念物必須遷移者", "土地改良物所有權人要求取回，並自公告期滿之日起15日內自行遷移者", "農作改良物之種類或數量與正常種植情形相當者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00519', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，關於土地徵收之程序，下列何者錯誤？', '["徵收土地或土地改良物，由中央主管機關核准之", "被徵收土地或土地改良物之所有權人，對於其土地或土地改良物之權利義務，於應徵收公告之日 終止", "徵收土地或土地改良物應發給之補償費，由需用土地人負擔，並繳交該管直轄市或縣（市）主管 機關轉發之", "中央主管機關為審議徵收案件，應遴聘（派）專家學者、民間團體及相關機關代表，以合議制方 式辦理之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00520', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，關於土地徵收，下列敘述何者錯誤？', '["徵收補償費發給完竣屆滿 1 年，未依徵收計畫開始使用者，原土地所有權人得於徵收公告之日起 20年內，向該管直轄市或縣（市）主管機關申請照原徵收補償價額收回其土地", "權利關係人對於徵收補償價額有異議者，得於公告期間屆滿之次日起30日內以書面向該管直轄市 或縣（市）主管機關提出異議", "共有分管之耕地，部分被徵收者，土地所有權人得於徵收補償地價發給完竣前或核定發給抵價地 前，申請共有物分割登記或應有部分交換移轉登記", "各直轄市、縣（市）主管機關應經常調查轄區地價動態，每 6 個月提交地價評議委員會評定被徵 收土地市價變動幅度，作為調整徵收補償地價之依據"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00521', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例之規定，抵價地總面積，以徵收總面積「一定比例」為原則。因情況特殊，經上級 主管機關核准者，不在此限。但不得少於「一定比例」。曾經農地重劃者，該重劃地區部分不得少 於「一定比例」。前述之一定比例，依序應為多少？', '["百分之四十、百分之五十、百分之六十", "百分之五十、百分之四十五、百分之四十", "百分之五十、百分之四十、百分之四十五", "百分之四十、百分之三十五、百分之四十五"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00522', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例之規定，關於區段徵收範圍內土地之處理，下列敘述何者錯誤？', '["區段徵收範圍內之公有土地，管理機關應以作價或領回土地方式撥供該管區段徵收主管機關統籌 規劃開發、分配", "區段徵收範圍內得規劃配設農業專用區，作為農業耕作使用", "道路、溝渠、公園、綠地、兒童遊樂場、廣場、停車場、體育場所及國民學校用地，無償登記為 當地直轄市有、縣（市）有或鄉（鎮、市）有", "國民住宅用地、安置原住戶或經行政院專案核准所需土地得予標售、標租或設定地上權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00523', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例第34條之1規定，徵收公告多久時間前有居住事實之低收入戶或中低收入戶人口， 因其所有建築改良物被徵收，致無屋可居住者，需用土地人應訂定安置計畫，並於徵收計畫書內敘 明安置計畫情形？', '["6個月", "1年", "1年6個月", "2年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00524', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例之規定，直轄市或縣（市）主管機關應設土地徵收補償費保管專戶。下列關於保管 專戶相關事項之敘述，何者正確？', '["主要是保管因受領遲延、拒絕受領或不能受領之補償費", "直轄市或縣（市）主管機關應於本條例規定應發給補償費之期限屆滿次日起1個月內存入專戶保管", "自存入專戶保管，通知送達應受補償人發生效力之日起，逾10年未領取之補償費，歸屬國庫", "保管專戶儲存之補償費不給付利息"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00525', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '設定農育權，除以造林、保育為目的或法令另有規定者外，其期限依規定不得逾幾年？', '["3年", "5年", "10年", "20年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00526', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅法規定，農業用地閒置不用，經加徵荒地稅滿幾年仍未使用者，直轄市、縣（市）政府得 照價收買？', '["1年", "2年", "3年", "4年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00527', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '下列有關典權之敘述，何者錯誤？', '["典權約定期限不得逾30年", "出典人設定典權後，不得將典物讓與他人", "出典人將典物出賣於他人時，典權人有以相同條件留買之權", "典期屆滿後，經過2年，出典人不以原典價回贖者，典權人取得典物所有權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
